css:
.exn{height:100%;box-sizing:border-box;overflow:auto;font-family:var(--font-stack-primary,system-ui,-apple-system,sans-serif);}
.exn-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(258px,1fr));gap:14px;}
.exn-card{display:flex;flex-direction:column;gap:3px;text-decoration:none;background:#fff;border:1px solid rgba(0,0,0,.08);border-left:4px solid var(--color-primary,#009fe4);border-radius:12px;box-shadow:0 1px 3px rgba(16,24,40,.06);padding:16px 18px;transition:transform .12s ease,box-shadow .12s ease;color:var(--color-text,#1f2937);}
.exn-card:hover{transform:translateY(-2px);box-shadow:0 8px 20px rgba(16,24,40,.13);}
.exn-card .ind{font-size:10.5px;letter-spacing:.08em;text-transform:uppercase;color:var(--color-primary,#009fe4);font-weight:800;}
.exn-card .name{font-size:16px;font-weight:800;margin-top:1px;}
.exn-card .metric{font-size:25px;font-weight:800;margin-top:8px;line-height:1;letter-spacing:-.01em;}
.exn-card .sub{font-size:12px;color:#6b7280;font-weight:600;margin-top:2px;}
.exn-card .go{margin-top:10px;font-size:12px;font-weight:700;color:var(--color-primary,#009fe4);}
